#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; long long a,b,c,d;
        scanf("%lld", &N);
        scanf("%lld %lld %lld %lld", &a, &b, &c, &d);
        long long ans = a;
        if(b>ans) ans=b;
        if(c>ans) ans=c;
        if(d>ans) ans=d;
        printf("%lld\n", ans);
    }
    return 0;
}

