import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))  # not used
        a = int(next(it)); b = int(next(it)); c = int(next(it)); d = int(next(it))
        out.append(str(max(a, b, c, d)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

